//  EmployeeDirectoryView.swift
//  Riverhead NY Budget App
//
//  Swift 6 / iOS 17+
//  Employee earnings directory pulled from Newsday gross earnings reports
//  (2018–2023). Search by name or File Number (employee ID).
//

import SwiftUI
import Charts

// MARK: - Models

struct EmployeeYearlyEarnings: Codable, Hashable {
    let gross: Double
    let regular: Double
    let overtime: Double
}

struct Employee: Codable, Identifiable, Hashable {
    var id: String { fileNumber.isEmpty ? name : fileNumber }

    let name: String
    let fileNumber: String
    let hireDate: String
    let status: String
    let terminationDate: String
    let union: String
    let department: String
    let jobTitle: String
    let earnings: [String: EmployeeYearlyEarnings]

    // MARK: Derived helpers

    var displayName: String {
        let parts = name.split(separator: ",", maxSplits: 1)
        if parts.count == 2 {
            return "\(parts[1].trimmingCharacters(in: .whitespaces)) \(parts[0])"
        }
        return name
    }

    var initials: String {
        let words = displayName.split(separator: " ")
        return words.prefix(2).compactMap(\.first).map(String.init).joined()
    }

    var peakGross: Double {
        earnings.values.map(\.gross).max() ?? 0
    }

    var totalGross: Double {
        earnings.values.reduce(0) { $0 + $1.gross }
    }

    var peakYear: String {
        earnings.max(by: { $0.value.gross < $1.value.gross })?.key ?? "—"
    }

    var sortedEarnings: [(year: String, data: EmployeeYearlyEarnings)] {
        earnings.map { (year: $0.key, data: $0.value) }
                .sorted { $0.year < $1.year }
    }

    var statusColor: Color {
        switch status {
        case "Active":     return .green
        case "Terminated": return .red
        case "Retired":    return .blue
        case "Deceased":   return Color(.systemGray)
        case "Leave":      return .orange
        default:           return Color(.systemGray2)
        }
    }

    var statusSymbol: String {
        switch status {
        case "Active":     return "checkmark.circle.fill"
        case "Terminated": return "xmark.circle.fill"
        case "Retired":    return "moon.fill"
        case "Deceased":   return "heart.fill"
        case "Leave":      return "clock.fill"
        default:           return "circle.fill"
        }
    }

    var laborGroup: LaborGroup {
        LaborGroup.infer(department: department, title: jobTitle, unionCode: union, defaultGroup: .exempt)
    }

    var bargainingUnitCode: String {
        switch laborGroup {
        case .pba: return "PBA"
        case .soa: return "SOA"
        case .csea: return "CSE"
        case .exempt: return "EXEMPT"
        }
    }

    var bargainingUnitLabel: String {
        switch laborGroup {
        case .pba: return "Police Benevolent Assoc."
        case .soa: return "Superior Officers Assoc."
        case .csea: return "CSEA"
        case .exempt: return "Exempt"
        }
    }

    var unionFullName: String {
        switch bargainingUnitCode {
        case "PBA": return "Police Benevolent Assoc."
        case "CSE": return "CSEA"
        case "SOA": return "Superior Officers Assoc."
        case "EXEMPT": return "Exempt"
        default:    return bargainingUnitLabel
        }
    }

    var countsAsActiveEmployee: Bool {
        status.trimmingCharacters(in: .whitespacesAndNewlines).localizedCaseInsensitiveCompare("Active") == .orderedSame
        && terminationDate.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    var avatarGradient: LinearGradient {
        let palettes: [[Color]] = [
            [Color(red: 0.22, green: 0.35, blue: 0.78), Color(red: 0.12, green: 0.22, blue: 0.55)],
            [Color(red: 0.55, green: 0.22, blue: 0.78), Color(red: 0.35, green: 0.12, blue: 0.55)],
            [Color(red: 0.78, green: 0.22, blue: 0.38), Color(red: 0.55, green: 0.12, blue: 0.25)],
            [Color(red: 0.18, green: 0.62, blue: 0.55), Color(red: 0.10, green: 0.40, blue: 0.35)],
            [Color(red: 0.75, green: 0.45, blue: 0.08), Color(red: 0.55, green: 0.28, blue: 0.05)],
            [Color(red: 0.10, green: 0.48, blue: 0.72), Color(red: 0.06, green: 0.28, blue: 0.50)],
        ]
        let idx = abs(name.hashValue) % palettes.count
        let pair = palettes[idx]
        return LinearGradient(colors: pair, startPoint: .topLeading, endPoint: .bottomTrailing)
    }
}

// MARK: - Store

@MainActor
final class EmployeeStore: ObservableObject {
    static let shared = EmployeeStore()

    @Published private(set) var employees: [Employee] = []
    @Published private(set) var isLoaded = false

    private init() {
        Task.detached(priority: .userInitiated) {
            let decoded = Self.decode()
            await MainActor.run {
                self.employees = decoded
                self.isLoaded = true
            }
        }
    }

    private nonisolated static func decode() -> [Employee] {
        guard let data = employeeJSON.data(using: .utf8) else { return [] }
        let decoded = (try? JSONDecoder().decode([Employee].self, from: data)) ?? []
        return deduplicated(decoded)
    }

    private nonisolated static func deduplicated(_ employees: [Employee]) -> [Employee] {
        let idMerged = mergeGroups(
            employees,
            key: { stableEmployeeID($0) },
            shouldMerge: { $0 != nil }
        )
        return mergeGroups(
            idMerged,
            key: { canonicalNameKey($0.name) },
            shouldMerge: { key in
                guard let key, !key.isEmpty else { return false }
                let matches = idMerged.filter { canonicalNameKey($0.name) == key }
                guard matches.count > 1 else { return false }
                return hasNoOverlappingEarningYears(matches)
            }
        )
    }

    private nonisolated static func mergeGroups(
        _ employees: [Employee],
        key: (Employee) -> String?,
        shouldMerge: (String?) -> Bool
    ) -> [Employee] {
        var grouped: [String: [Employee]] = [:]
        var passthrough: [Employee] = []

        for employee in employees {
            guard let groupKey = key(employee), shouldMerge(groupKey) else {
                passthrough.append(employee)
                continue
            }
            grouped[groupKey, default: []].append(employee)
        }

        let merged = grouped.values.map { group in
            group.count == 1 ? group[0] : merge(group)
        }
        return (passthrough + merged).sorted { $0.displayName < $1.displayName }
    }

    private nonisolated static func merge(_ employees: [Employee]) -> Employee {
        let preferred = employees.max { lhs, rhs in
            latestYear(lhs) < latestYear(rhs)
        } ?? employees[0]
        let oldest = employees.min { lhs, rhs in
            hireDateSortKey(lhs.hireDate) < hireDateSortKey(rhs.hireDate)
        } ?? preferred
        let stableID = employees.compactMap(stableEmployeeID).sorted().first
        var earnings: [String: EmployeeYearlyEarnings] = [:]

        for employee in employees {
            for (year, value) in employee.earnings {
                if let existing = earnings[year] {
                    earnings[year] = value.gross >= existing.gross ? value : existing
                } else {
                    earnings[year] = value
                }
            }
        }

        return Employee(
            name: preferred.name,
            fileNumber: stableID ?? preferred.fileNumber,
            hireDate: oldest.hireDate.isEmpty ? preferred.hireDate : oldest.hireDate,
            status: preferred.status,
            terminationDate: preferred.terminationDate,
            union: preferred.union.isEmpty ? employees.first { !$0.union.isEmpty }?.union ?? "" : preferred.union,
            department: preferred.department.isEmpty ? employees.first { !$0.department.isEmpty }?.department ?? "" : preferred.department,
            jobTitle: preferred.jobTitle.isEmpty ? employees.first { !$0.jobTitle.isEmpty }?.jobTitle ?? "" : preferred.jobTitle,
            earnings: earnings
        )
    }

    private nonisolated static func stableEmployeeID(_ employee: Employee) -> String? {
        let id = employee.fileNumber.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !id.isEmpty, id != employee.name else { return nil }
        return id
    }

    private nonisolated static func latestYear(_ employee: Employee) -> Int {
        employee.earnings.keys.compactMap(Int.init).max() ?? 0
    }

    private nonisolated static func hireDateSortKey(_ value: String) -> Int {
        let parts = value.split(separator: "/").compactMap { Int($0) }
        guard parts.count == 3 else { return Int.max }
        return parts[2] * 10_000 + parts[0] * 100 + parts[1]
    }

    private nonisolated static func canonicalNameKey(_ name: String) -> String? {
        let cleaned = name
            .lowercased()
            .replacingOccurrences(of: "[^a-z, ]", with: " ", options: .regularExpression)
            .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let pieces = cleaned.split(separator: ",", maxSplits: 1).map(String.init)
        guard pieces.count == 2 else { return nil }
        let first = pieces[1].split(separator: " ").first.map(String.init) ?? ""
        guard !pieces[0].isEmpty, !first.isEmpty else { return nil }
        return "\(pieces[0]),\(first)"
    }

    private nonisolated static func hasNoOverlappingEarningYears(_ employees: [Employee]) -> Bool {
        var years = Set<String>()
        for employee in employees {
            for year in employee.earnings.keys {
                if years.contains(year) { return false }
                years.insert(year)
            }
        }
        return true
    }
}

// MARK: - Root View

@MainActor
struct EmployeeDirectoryView: View {
    @StateObject private var store     = EmployeeStore.shared
    @StateObject private var analytics = WorkforceAnalytics.shared

    @State private var searchText       = ""
    @State private var filterStatus     = "All"
    @State private var filterUnion      = "All"
    @State private var sortMode         = SortMode.nameAZ
    @State private var selected: Employee?
    @State private var showDashboard    = false
    @State private var quickLook: Employee?

    @Environment(\.colorScheme) private var scheme

    private let statusOptions = ["All", "Active", "Terminated", "Retired", "Leave", "Deceased"]
    private var unionOptions: [String] {
        let codes = Set(store.employees.map(\.bargainingUnitCode).filter { !$0.isEmpty })
        return ["All"] + codes.sorted()
    }

    enum SortMode: String, CaseIterable, Identifiable {
        case nameAZ   = "Name A–Z"
        case nameZA   = "Name Z–A"
        case earningsHigh = "Highest Paid"
        case earningsLow  = "Lowest Paid"

        var id: String { rawValue }
        var symbol: String {
            switch self {
            case .nameAZ:       return "textformat"
            case .nameZA:       return "textformat"
            case .earningsHigh: return "arrow.down.circle"
            case .earningsLow:  return "arrow.up.circle"
            }
        }
    }

    private var filtered: [Employee] {
        let base = store.employees.filter { emp in
            let q = searchText.trimmingCharacters(in: .whitespaces)
            let matchSearch = q.isEmpty
                || emp.name.localizedCaseInsensitiveContains(q)
                || emp.displayName.localizedCaseInsensitiveContains(q)
                || emp.fileNumber.localizedCaseInsensitiveContains(q)
            let matchStatus = filterStatus == "All" || emp.status == filterStatus
            let matchUnion = filterUnion == "All" || emp.bargainingUnitCode == filterUnion
            return matchSearch && matchStatus && matchUnion
        }
        switch sortMode {
        case .nameAZ:       return base.sorted { $0.displayName < $1.displayName }
        case .nameZA:       return base.sorted { $0.displayName > $1.displayName }
        case .earningsHigh: return base.sorted { $0.peakGross > $1.peakGross }
        case .earningsLow:  return base.sorted { $0.peakGross < $1.peakGross }
        }
    }

    var body: some View {
        NavigationSplitView(columnVisibility: .constant(.all)) {
            sidebarContent
                .navigationTitle("Employee Directory")
                .navigationBarTitleDisplayMode(.inline)
                .toolbar {
                    ToolbarItem(placement: .topBarTrailing) {
                        Button {
                            showDashboard = true
                        } label: {
                            Image(systemName: "chart.bar.doc.horizontal")
                                .accessibilityLabel("Workforce Analytics")
                        }
                    }
                }
                .sheet(isPresented: $showDashboard) {
                    NavigationStack { WorkforceDashboardView() }
                }
                .sheet(item: $quickLook) { emp in
                    EmployeeQuickLookView(employee: emp)
                }
                .toolbarBackground(
                    RiverheadTheme.Surface.card.opacity(scheme == .dark ? 0.95 : 1.0),
                    for: .navigationBar
                )
                .toolbarBackground(.visible, for: .navigationBar)
                .onReceive(store.$isLoaded) { loaded in
                    if loaded { analytics.compute(from: store.employees) }
                }
        } detail: {
            if let emp = selected {
                EmployeeDetailView(employee: emp)
            } else {
                directoryEmptyState
            }
        }
    }

    // MARK: Sidebar

    private var sidebarContent: some View {
        VStack(spacing: 0) {
            directoryHero
                .padding(.horizontal, 16)
                .padding(.top, 8)
                .padding(.bottom, 12)

            searchBar
                .padding(.horizontal, 16)
                .padding(.bottom, 8)

            statusChips
                .padding(.bottom, 4)

            unionFilter
                .padding(.horizontal, 16)
                .padding(.bottom, 4)

            sortBar
                .padding(.horizontal, 16)
                .padding(.bottom, 4)

            if analytics.isReady {
                AnalyticsStripView()
                    .padding(.bottom, 4)
            }

            Divider().opacity(0.35)

            if store.isLoaded {
                employeeList
            } else {
                Spacer()
                ProgressView("Loading records…")
                    .foregroundStyle(RiverheadTheme.textSecondary)
                Spacer()
            }
        }
        .background(RiverheadTheme.Surface.page.ignoresSafeArea())
    }

    // MARK: Hero

    private var directoryHero: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text("Gross Earnings")
                .font(.caption.weight(.semibold))
                .foregroundStyle(.white.opacity(0.85))

            Text("Employee Directory")
                .font(.system(.title2, design: .rounded).weight(.bold))
                .foregroundStyle(.white)

            HStack(spacing: 6) {
                if store.isLoaded {
                    Text("\(filtered.count) records · \(store.employees.filter(\.countsAsActiveEmployee).count) active employees")
                        .font(.footnote)
                        .foregroundStyle(.white.opacity(0.85))
                } else {
                    Text("Loading Newsday earnings data…")
                        .font(.footnote)
                        .foregroundStyle(.white.opacity(0.75))
                }
            }
        }
        .padding(16)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(
            LinearGradient(
                colors: [
                    RiverheadTheme.primaryBlue.opacity(0.95),
                    Color.black.opacity(0.75)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
        )
        .overlay(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .strokeBorder(Color.white.opacity(0.18), lineWidth: 0.8)
        )
        .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
        .shadow(
            color: .black.opacity(scheme == .dark ? 0.55 : 0.18),
            radius: 18, x: 0, y: 10
        )
    }

    // MARK: Search

    private var searchBar: some View {
        HStack(spacing: 8) {
            Image(systemName: "magnifyingglass")
                .foregroundStyle(RiverheadTheme.textSecondary)
                .font(.subheadline)
            TextField("Search name or employee ID…", text: $searchText)
                .font(.subheadline)
                .autocorrectionDisabled()
                .textInputAutocapitalization(.never)
                .submitLabel(.search)
            if !searchText.isEmpty {
                Button { searchText = "" } label: {
                    Image(systemName: "xmark.circle.fill")
                        .foregroundStyle(RiverheadTheme.textSecondary)
                }
                .buttonStyle(.plain)
            }
        }
        .padding(10)
        .background(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .fill(scheme == .dark ? Color.black.opacity(0.55) : RiverheadTheme.Surface.card)
        )
        .overlay(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .strokeBorder(RiverheadTheme.border.opacity(scheme == .dark ? 0.35 : 0.2))
        )
    }

    // MARK: Status chips

    private var statusChips: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 8) {
                ForEach(statusOptions, id: \.self) { status in
                    let active = filterStatus == status
                    Button { filterStatus = status } label: {
                        Text(status)
                            .font(.footnote.weight(.medium))
                            .padding(.horizontal, 12)
                            .padding(.vertical, 6)
                            .background(
                                Capsule().fill(
                                    active
                                    ? RiverheadTheme.accent.opacity(0.18)
                                    : RiverheadTheme.Surface.card.opacity(0.95)
                                )
                            )
                            .overlay(
                                Capsule().strokeBorder(
                                    (active ? RiverheadTheme.accent : RiverheadTheme.border)
                                        .opacity(0.35),
                                    lineWidth: 0.8
                                )
                            )
                            .foregroundStyle(
                                active ? RiverheadTheme.accent : RiverheadTheme.textPrimary
                            )
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 4)
        }
    }

    // MARK: Union filter

    private var unionFilter: some View {
        HStack(spacing: 8) {
            Image(systemName: "person.2.fill")
                .font(.caption)
                .foregroundStyle(RiverheadTheme.textSecondary)
            Picker("Bargaining Unit", selection: $filterUnion) {
                ForEach(unionOptions, id: \.self) { code in
                    Text(code == "All" ? "All Units" : UnionSnapshot.fullName(for: code))
                        .tag(code)
                }
            }
            .pickerStyle(.menu)
            .font(.footnote)
            Spacer()
        }
    }

    // MARK: Sort bar

    private var sortBar: some View {
        HStack(spacing: 8) {
            Image(systemName: "arrow.up.arrow.down")
                .font(.caption)
                .foregroundStyle(RiverheadTheme.textSecondary)
            Picker("Sort", selection: $sortMode) {
                ForEach(SortMode.allCases) { mode in
                    Text(mode.rawValue).tag(mode)
                }
            }
            .pickerStyle(.menu)
            .font(.footnote)
            Spacer()
        }
    }

    // MARK: Employee list

    private var employeeList: some View {
        List(filtered, selection: $selected) { employee in
            EmployeeRowView(employee: employee, onQuickLook: { quickLook = employee })
                .tag(employee)
                .listRowInsets(EdgeInsets(top: 5, leading: 12, bottom: 5, trailing: 12))
                .listRowBackground(Color.clear)
        }
        .listStyle(.plain)
        .scrollContentBackground(.hidden)
    }

    // MARK: Empty state

    private var directoryEmptyState: some View {
        VStack(spacing: 16) {
            Image(systemName: "person.text.rectangle.fill")
                .font(.system(size: 56))
                .foregroundStyle(RiverheadTheme.accent.opacity(0.4))
            Text("Select an Employee")
                .font(.system(.title2, design: .rounded).weight(.bold))
                .foregroundStyle(RiverheadTheme.textPrimary)
            Text("Choose a record from the list to view\nearnings history, department info, and more.")
                .font(.footnote)
                .foregroundStyle(RiverheadTheme.textSecondary)
                .multilineTextAlignment(.center)

            Button {
                showDashboard = true
            } label: {
                Label("View Workforce Analytics", systemImage: "chart.bar.doc.horizontal")
                    .font(.footnote.weight(.semibold))
                    .padding(.horizontal, 18)
                    .padding(.vertical, 10)
                    .background(RiverheadTheme.accent.opacity(0.12))
                    .foregroundStyle(RiverheadTheme.accent)
                    .clipShape(Capsule())
                    .overlay(Capsule().strokeBorder(RiverheadTheme.accent.opacity(0.3)))
            }
            .buttonStyle(.plain)
            .padding(.top, 4)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(RiverheadTheme.Surface.page.ignoresSafeArea())
    }
}

// MARK: - Row View

private struct EmployeeRowView: View {
    let employee: Employee
    let onQuickLook: () -> Void

    @Environment(\.colorScheme) private var scheme

    var body: some View {
        HStack(spacing: 12) {
            avatarCircle

            VStack(alignment: .leading, spacing: 3) {
                Text(employee.displayName)
                    .font(.subheadline.weight(.semibold))
                    .foregroundStyle(RiverheadTheme.textPrimary)
                    .lineLimit(1)

                HStack(spacing: 6) {
                    if !employee.fileNumber.isEmpty && employee.fileNumber != employee.name {
                        Text("ID \(employee.fileNumber)")
                            .font(.caption2.weight(.medium))
                            .foregroundStyle(RiverheadTheme.textSecondary)
                            .fontDesign(.monospaced)
                    }
                    if employee.laborGroup != .exempt {
                        Text(employee.bargainingUnitCode)
                            .font(.caption2.weight(.bold))
                            .padding(.horizontal, 5)
                            .padding(.vertical, 1)
                            .background(RiverheadTheme.accent.opacity(0.12))
                            .foregroundStyle(RiverheadTheme.accent)
                            .clipShape(Capsule())
                    }
                }
            }

            Spacer()

            VStack(alignment: .trailing, spacing: 4) {
                if employee.peakGross > 0 {
                    Text(employee.peakGross, format: .currency(code: "USD").precision(.fractionLength(0)))
                        .font(.footnote.weight(.semibold))
                        .foregroundStyle(RiverheadTheme.textPrimary)
                        .fontDesign(.monospaced)
                }
                Image(systemName: employee.statusSymbol)
                    .font(.system(size: 7))
                    .foregroundStyle(employee.statusColor)
            }
        }
        .padding(.vertical, 4)
        .padding(.horizontal, 8)
        .background(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .fill(scheme == .dark ? Color.white.opacity(0.03) : Color.white.opacity(0.6))
        )
        .onTapGesture(count: 2) {
            onQuickLook()
        }
        .contextMenu {
            Button {
                onQuickLook()
            } label: {
                Label("Quick Look", systemImage: "person.crop.rectangle.badge.plus")
            }
            Button {
                UIPasteboard.general.string = employee.displayName
            } label: {
                Label("Copy Name", systemImage: "doc.on.doc")
            }
            if !employee.fileNumber.isEmpty && employee.fileNumber != employee.name {
                Button {
                    UIPasteboard.general.string = employee.fileNumber
                } label: {
                    Label("Copy Employee ID", systemImage: "number")
                }
            }
        }
    }

    private var avatarCircle: some View {
        ZStack {
            Circle().fill(employee.avatarGradient)
            Text(employee.initials)
                .font(.system(size: 13, weight: .bold))
                .foregroundStyle(.white)
        }
        .frame(width: 40, height: 40)
    }
}

// MARK: - Quick Look Sheet

@MainActor
struct EmployeeQuickLookView: View {
    let employee: Employee

    @Environment(\.dismiss) private var dismiss
    @Environment(\.colorScheme) private var scheme
    @Environment(\.accessibilityReduceTransparency) private var reduceTransparency

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 16) {
                    avatarHeader
                    statsRow
                    earningsSpark
                    infoGrid
                    yearTable
                }
                .padding(.horizontal, 18)
                .padding(.top, 12)
                .padding(.bottom, 32)
            }
            .background(RiverheadTheme.Surface.page.ignoresSafeArea())
            .navigationTitle("Quick Look")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("Done") { dismiss() }
                        .fontWeight(.semibold)
                }
            }
        }
        .presentationDetents([.medium, .large])
        .presentationDragIndicator(.visible)
    }

    // MARK: Avatar + name

    private var avatarHeader: some View {
        VStack(spacing: 10) {
            ZStack {
                Circle()
                    .fill(employee.avatarGradient)
                    .frame(width: 72, height: 72)
                Text(employee.initials)
                    .font(.system(size: 26, weight: .black))
                    .foregroundStyle(.white)
            }

            Text(employee.displayName)
                .font(.system(.title3, design: .rounded).weight(.bold))
                .foregroundStyle(RiverheadTheme.textPrimary)
                .multilineTextAlignment(.center)

            HStack(spacing: 8) {
                if !employee.jobTitle.isEmpty {
                    Text(employee.jobTitle)
                        .font(.footnote)
                        .foregroundStyle(RiverheadTheme.textSecondary)
                }
                if !employee.jobTitle.isEmpty && !employee.department.isEmpty {
                    Text("·").foregroundStyle(RiverheadTheme.textSecondary).font(.footnote)
                }
                if !employee.department.isEmpty {
                    Text(employee.department)
                        .font(.footnote)
                        .foregroundStyle(RiverheadTheme.textSecondary)
                }
            }
            .multilineTextAlignment(.center)

            Label(employee.status, systemImage: employee.statusSymbol)
                .font(.caption.weight(.semibold))
                .foregroundStyle(employee.statusColor)
                .padding(.horizontal, 12)
                .padding(.vertical, 5)
                .background(employee.statusColor.opacity(0.12))
                .clipShape(Capsule())
        }
    }

    // MARK: Key stats row

    private var statsRow: some View {
        HStack(spacing: 8) {
            quickTile(
                icon: "dollarsign.circle.fill",
                label: "Peak Year Gross",
