// MARK: - Embedded JSON data


// MARK: - Workforce Analytics Engine

struct WorkforceYearSnapshot: Identifiable {
    let id: String           // year string e.g. "2023"
    let year: String
    let headcount: Int
    let avgGross: Double
    let medianGross: Double
    let totalGross: Double
    let totalRegular: Double
    let totalOther: Double   // gross - regular (OT is negligible in this dataset)
    let newHires: Int        // appeared this year, not in prior year
    let departures: Int      // were in prior year, not this year
}

struct PBAEarnerSnapshot: Identifiable {
    let id: String
    let name: String
    let gross: Double
    let regular: Double
    let premium: Double
}

struct PBAPremiumSnapshot {
    let year: String
    let grossPayees: Int
    let basePayees: Int
    let highPremiumCount: Int
    let highPremiumTotal: Double
    let topEarners: [PBAEarnerSnapshot]
}

struct UnionSnapshot: Identifiable {
    let id: String           // union code
    let code: String
    let fullName: String
    let headcount: Int
    let avgGross: Double
    let medianGross: Double

    static func fullName(for code: String) -> String {
        switch code {
        case "PBA": return "Police Benevolent Assoc."
        case "CSE": return "CSEA"
        case "SOA": return "Superior Officers Assoc."
        case "EXEMPT": return "Exempt"
        default:    return code.isEmpty ? "Unknown" : code
        }
    }
}

struct StatusBreakdown: Identifiable {
    let id: String  // status string
    let status: String
    let count: Int
    let color: Color
}

@MainActor
final class WorkforceAnalytics: ObservableObject {
    static let shared = WorkforceAnalytics()

    @Published private(set) var yearSnapshots: [WorkforceYearSnapshot] = []
    @Published private(set) var unionSnapshots: [UnionSnapshot] = []
    @Published private(set) var statusBreakdown: [StatusBreakdown] = []
    @Published private(set) var pbaSnapshot: PBAPremiumSnapshot?
    @Published private(set) var isReady = false

    nonisolated private static let allYears = ["2018","2019","2020","2021","2022","2023"]
    nonisolated private static let sourceReportHeadcounts = ["2023": 802]

    private init() {}

    /// Call once the EmployeeStore has finished loading.
    func compute(from employees: [Employee]) {
        guard !isReady else { return }
        Task.detached(priority: .utility) {
            let (years, unions, statuses, pba) = Self.crunch(employees)
            await MainActor.run {
                self.yearSnapshots  = years
                self.unionSnapshots = unions
                self.statusBreakdown = statuses
                self.pbaSnapshot = pba
                self.isReady = true
            }
        }
    }

    // MARK: - Pure computation (off main thread)

    private nonisolated static func crunch(
        _ employees: [Employee]
    ) -> ([WorkforceYearSnapshot], [UnionSnapshot], [StatusBreakdown], PBAPremiumSnapshot?) {

        // ── Year snapshots ──────────────────────────────────────────────
        var yearSnaps: [WorkforceYearSnapshot] = []
        var prevNames: Set<String> = []

        for (idx, year) in allYears.enumerated() {
            let yearRows = employees.filter { $0.earnings[year] != nil }
            let paidRows = yearRows.filter { ($0.earnings[year]?.gross ?? 0) > 0 }
            let grosses = paidRows.map { $0.earnings[year]!.gross }.sorted()
            let grossCount = grosses.count
            let headcount = sourceReportHeadcounts[year] ?? yearRows.count
            guard headcount > 0, grossCount > 0 else { continue }

            let avg    = grosses.reduce(0, +) / Double(grossCount)
            let median = grossCount % 2 == 0
                ? (grosses[grossCount/2 - 1] + grosses[grossCount/2]) / 2
                : grosses[grossCount/2]
            let totalGross   = grosses.reduce(0, +)
            let totalRegular = paidRows.reduce(0) { $0 + ($1.earnings[year]?.regular ?? 0) }
            let totalOther   = totalGross - totalRegular

            let names = Set(yearRows.map(\.name))
            let newHires   = idx == 0 ? headcount : names.subtracting(prevNames).count
            let departures = idx == 0 ? 0 : prevNames.subtracting(names).count
            prevNames = names

            yearSnaps.append(WorkforceYearSnapshot(
                id: year,
                year: year,
                headcount: headcount,
                avgGross: avg,
                medianGross: median,
                totalGross: totalGross,
                totalRegular: totalRegular,
                totalOther: totalOther,
                newHires: newHires,
                departures: departures
            ))
        }

        // ── Union snapshots (most recent year with data, 2023) ──────────
        let refYear = allYears.last ?? "2023"
        var byUnion: [String: [Double]] = [:]
        for emp in employees {
            guard emp.countsAsActiveEmployee, let e = emp.earnings[refYear], e.gross > 0 else { continue }
            let code = emp.bargainingUnitCode
            byUnion[code, default: []].append(e.gross)
        }
        let unionSnaps: [UnionSnapshot] = byUnion.compactMap { code, grosses in
            guard !grosses.isEmpty else { return nil }
            let sorted = grosses.sorted()
            let n = sorted.count
            let avg = sorted.reduce(0, +) / Double(n)
            let med = n % 2 == 0
                ? (sorted[n/2 - 1] + sorted[n/2]) / 2
                : sorted[n/2]
            return UnionSnapshot(
                id: code,
                code: code,
                fullName: UnionSnapshot.fullName(for: code),
                headcount: n,
                avgGross: avg,
                medianGross: med
            )
        }
        .filter { $0.code != "EXEMPT" && !$0.code.isEmpty }
        .sorted { $0.medianGross > $1.medianGross }

        // ── Status breakdown ─────────────────────────────────────────────
        var statusCounts: [String: Int] = [:]
        for emp in employees {
            let s = emp.status.isEmpty ? "Unknown" : emp.status
            statusCounts[s, default: 0] += 1
        }
        let statusColors: [String: Color] = [
            "Active":     .green,
            "Terminated": .red,
            "Retired":    .blue,
            "Deceased":   Color(.systemGray),
            "Leave":      .orange
        ]
        let statusSnaps = statusCounts
            .map { StatusBreakdown(
                id: $0.key,
                status: $0.key,
                count: $0.value,
                color: statusColors[$0.key] ?? Color(.systemGray2)
            )}
            .sorted { $0.count > $1.count }

        let pbaRows = employees
            .filter { employee in
                guard let earnings = employee.earnings[refYear], earnings.gross > 0 else { return false }
                return employee.union.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() == "PBA"
            }
        let pbaBaseRows = pbaRows.filter { ($0.earnings[refYear]?.regular ?? 0) > 0 }
        let highPremiumRows = pbaBaseRows.filter { employee in
            guard let earnings = employee.earnings[refYear] else { return false }
            return earnings.gross - earnings.regular > earnings.regular * 0.5
        }
        let topPBAEarners = pbaRows
            .sorted { ($0.earnings[refYear]?.gross ?? 0) > ($1.earnings[refYear]?.gross ?? 0) }
            .prefix(10)
            .map { employee -> PBAEarnerSnapshot in
                let earnings = employee.earnings[refYear] ?? EmployeeYearlyEarnings(gross: 0, regular: 0, overtime: 0)
                return PBAEarnerSnapshot(
                    id: employee.id,
                    name: employee.name,
                    gross: earnings.gross,
                    regular: earnings.regular,
                    premium: earnings.gross - earnings.regular
                )
            }
        let pbaSnapshot = PBAPremiumSnapshot(
            year: refYear,
            grossPayees: pbaRows.count,
            basePayees: pbaBaseRows.count,
            highPremiumCount: highPremiumRows.count,
            highPremiumTotal: highPremiumRows.reduce(0) { total, employee in
                guard let earnings = employee.earnings[refYear] else { return total }
                return total + earnings.gross - earnings.regular
            },
            topEarners: Array(topPBAEarners)
        )

        return (yearSnaps, unionSnaps, statusSnaps, pbaSnapshot)
    }
}

// MARK: - Workforce Dashboard View

@MainActor
struct WorkforceDashboardView: View {
    @StateObject private var store     = EmployeeStore.shared
    @StateObject private var analytics = WorkforceAnalytics.shared
    @Environment(\.colorScheme) private var scheme
    @Environment(\.accessibilityReduceTransparency) private var reduceTransparency

    var body: some View {
        ScrollView {
            if analytics.isReady {
                VStack(spacing: 16) {
                    payrollSummarySection
                    headcountSection
                    salarySection
                    pbaSection
                    turnoverSection
                    unionSection
                    statusSection
                }
                .padding(.horizontal, 16)
                .padding(.top, 16)
                .padding(.bottom, 32)
            } else {
                VStack(spacing: 12) {
                    Spacer().frame(height: 60)
                    ProgressView("Computing workforce analytics…")
                        .foregroundStyle(RiverheadTheme.textSecondary)
                }
                .frame(maxWidth: .infinity)
            }
        }
        .background(RiverheadTheme.Surface.page.ignoresSafeArea())
        .navigationTitle("Workforce Analytics")
        .navigationBarTitleDisplayMode(.inline)
        .toolbarBackground(
            RiverheadTheme.Surface.card.opacity(scheme == .dark ? 0.95 : 1.0),
            for: .navigationBar
        )
        .toolbarBackground(.visible, for: .navigationBar)
        .task {
            if !analytics.isReady && store.isLoaded {
                analytics.compute(from: store.employees)
            }
        }
        .onReceive(store.$isLoaded) { loaded in
            if loaded && !analytics.isReady {
                analytics.compute(from: store.employees)
            }
        }
