    private func pbaBudgetImplicationCard(_ pba: PBAPremiumSnapshot) -> some View {
        let policeRecord = DepartmentBudgetLensData.departmentRecords.first { $0.fundCode == "A01-3120" }
        let salaryBase = policeRecord?.salaryBase ?? 12_929_775.95
        let adoptedTotal = policeRecord?.adoptedTotal ?? 22_388_906
        let nonSalaryLayer = adoptedTotal - salaryBase
        let holidayPay2025 = 752_400.0
        let holidayPay2026 = 943_000.0
        let buyback2025 = 388_666.0
        let buyback2026 = 500_729.0
        let holidayGrowth = (holidayPay2026 - holidayPay2025) / holidayPay2025
        let buybackGrowth = (buyback2026 - buyback2025) / buyback2025
        let highPremiumShare = Double(pba.highPremiumCount) / Double(max(pba.grossPayees, 1))

        return VStack(alignment: .leading, spacing: 10) {
            HStack(alignment: .top, spacing: 8) {
                Image(systemName: "exclamationmark.triangle.fill")
                    .font(.subheadline)
                    .foregroundStyle(.orange)

                VStack(alignment: .leading, spacing: 6) {
                    Text("2026 budget implication")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(RiverheadTheme.textPrimary)

                    Text("Police 3120 books \(holidayPay2026.formatted(.currency(code: "USD").precision(.fractionLength(0)))) for holiday pay, up \(holidayGrowth.formatted(.percent.precision(.fractionLength(0)))), and \(buyback2026.formatted(.currency(code: "USD").precision(.fractionLength(0)))) for health-insurance buy-back, up \(buybackGrowth.formatted(.percent.precision(.fractionLength(0)))). With \(highPremiumShare.formatted(.percent.precision(.fractionLength(0)))) of PBA members carrying premium pay above 50% of base in 2023, the \(salaryBase.formatted(.currency(code: "USD").precision(.fractionLength(1)))) salary base likely understates all-in police payroll pressure before benefits are added.")
                        .font(.caption)
                        .foregroundStyle(RiverheadTheme.textSecondary)
                        .fixedSize(horizontal: false, vertical: true)

                    Text("Accountability ask: break the \(nonSalaryLayer.formatted(.currency(code: "USD").precision(.fractionLength(1)))) non-salary layer into explicit overtime and premium-pay estimates, benefits, vehicle/equipment support, and other operating costs.")
                        .font(.caption)
                        .foregroundStyle(RiverheadTheme.textSecondary)
                        .fixedSize(horizontal: false, vertical: true)
                }
            }
        }
        .padding(12)
        .background(Color.orange.opacity(0.10), in: RoundedRectangle(cornerRadius: 12, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .strokeBorder(Color.orange.opacity(0.25), lineWidth: 1)
        )
    }

