                        Text(snap.status)
                            .font(.footnote)
                            .foregroundStyle(RiverheadTheme.textPrimary)
                        Spacer()
                        Text("\(snap.count)")
                            .font(.footnote.weight(.semibold))
                            .fontDesign(.monospaced)
                            .foregroundStyle(RiverheadTheme.textPrimary)
                        Text(String(format: "%.0f%%", Double(snap.count) / total * 100))
                            .font(.caption2)
                            .foregroundStyle(RiverheadTheme.textSecondary)
                            .frame(width: 36, alignment: .trailing)
                    }
                    .padding(.vertical, 5)

                    if snap.id != analytics.statusBreakdown.last?.id {
                        Divider().opacity(0.2)
                    }
                }
            }
        }
        .padding(14)
        .background(dashCard())
    }

    // MARK: - Helpers

    private func dashLabel(_ text: String) -> some View {
        Text(text)
            .font(.caption2.weight(.semibold))
            .foregroundStyle(RiverheadTheme.textSecondary)
            .tracking(2)
    }

    @ViewBuilder
    private func dashCard() -> some View {
        RoundedRectangle(cornerRadius: 16, style: .continuous)
            .fill(
                reduceTransparency
                ? AnyShapeStyle(RiverheadTheme.Surface.card)
                : AnyShapeStyle(scheme == .dark ? .ultraThinMaterial : .regularMaterial)
            )
            .shadow(color: .black.opacity(scheme == .dark ? 0.25 : 0.06), radius: 10, x: 0, y: 4)
            .overlay(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .strokeBorder(RiverheadTheme.border.opacity(scheme == .dark ? 0.35 : 0.2))
            )
    }

    private func analyticTile(
        label: String, value: String, icon: String, accent: Color? = nil
    ) -> some View {
        VStack(spacing: 4) {
            Image(systemName: icon)
                .font(.caption)
                .foregroundStyle(accent ?? RiverheadTheme.accent)
            Text(value)
                .font(.system(.footnote, design: .rounded).weight(.black))
                .foregroundStyle(accent ?? RiverheadTheme.textPrimary)
                .fontDesign(.monospaced)
                .lineLimit(1)
                .minimumScaleFactor(0.7)
            Text(label)
                .font(.system(size: 9).weight(.medium))
                .foregroundStyle(RiverheadTheme.textSecondary)
                .multilineTextAlignment(.center)
                .lineLimit(2)
                .minimumScaleFactor(0.8)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 10)
        .background(
            RoundedRectangle(cornerRadius: 10, style: .continuous)
                .fill(RiverheadTheme.Surface.card.opacity(0.7))
                .overlay(
                    RoundedRectangle(cornerRadius: 10, style: .continuous)
                        .strokeBorder(RiverheadTheme.border.opacity(0.25))
                )
        )
    }

    private func insightPill(_ text: String, tint: Color) -> some View {
        Text(text)
            .font(.caption.weight(.semibold))
            .foregroundStyle(tint)
            .padding(.horizontal, 10)
            .padding(.vertical, 5)
            .background(tint.opacity(0.12))
            .clipShape(Capsule())
    }

    private func legendDot(color: Color, label: String) -> some View {
        HStack(spacing: 4) {
            Circle().fill(color).frame(width: 8, height: 8)
            Text(label)
                .font(.caption2)
                .foregroundStyle(RiverheadTheme.textSecondary)
        }
    }
}

// MARK: - Compact Analytics Strip (shown above employee list)

@MainActor
private struct AnalyticsStripView: View {
    @StateObject private var analytics = WorkforceAnalytics.shared
    @Environment(\.colorScheme) private var scheme

    var body: some View {
        if let last = analytics.yearSnapshots.last {
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 8) {
                    stripChip(
                        label: "\(last.year) Active",
                        value: "\(last.headcount)",
                        icon: "person.3.fill"
                    )
                    stripChip(
                        label: "Avg Gross",
                        value: last.avgGross.formatted(.currency(code: "USD").precision(.fractionLength(0))),
                        icon: "dollarsign.circle"
                    )
                    stripChip(
                        label: "Median Gross",
                        value: last.medianGross.formatted(.currency(code: "USD").precision(.fractionLength(0))),
                        icon: "chart.bar.xaxis"
                    )
                    if analytics.yearSnapshots.dropLast().last != nil {
                        let flow = last.newHires - last.departures
                        stripChip(
                            label: "Net Flow \(last.year)",
                            value: (flow >= 0 ? "+" : "") + "\(flow)",
                            icon: flow >= 0 ? "arrow.up.right.circle" : "arrow.down.right.circle"
                        )
                    }
                }
                .padding(.horizontal, 16)
                .padding(.vertical, 6)
            }
        }
    }

    private func stripChip(label: String, value: String, icon: String) -> some View {
        HStack(spacing: 5) {
            Image(systemName: icon)
                .font(.system(size: 10))
                .foregroundStyle(RiverheadTheme.accent)
            VStack(alignment: .leading, spacing: 1) {
                Text(value)
                    .font(.system(size: 12, weight: .bold, design: .rounded))
                    .foregroundStyle(RiverheadTheme.textPrimary)
                Text(label)
                    .font(.system(size: 9))
                    .foregroundStyle(RiverheadTheme.textSecondary)
            }
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 6)
        .background(
            RoundedRectangle(cornerRadius: 10, style: .continuous)
                .fill(scheme == .dark ? Color.white.opacity(0.05) : RiverheadTheme.Surface.card)
                .overlay(
                    RoundedRectangle(cornerRadius: 10, style: .continuous)
                        .strokeBorder(RiverheadTheme.border.opacity(0.25))
                )
        )
    }
}

